use std::error::Error;
use std::fmt::{self, Display};

struct SearchResult {
    id: u32,
    similarity_score: f64,
}

#[derive(Debug)]
struct DataProcessingError {
    message: String,
}

impl Display for DataProcessingError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Data processing failed: {}", self.message)
    }
}

impl Error for DataProcessingError {}

fn perform_search(query: &str, data_source: &[&str]) -> Result<Vec<SearchResult>, Box<dyn Error>> {
    if query.is_empty() {
        return Err(Box::new(DataProcessingError { message: "Query cannot be empty".to_string() }));
    }

    if data_source.len() < 2 {
        return Err(format!("Need at least two data points to run similarity search. Found {}", data_source.len()).into());
    }

    let results = vec![
        SearchResult { id: 1, similarity_score: 0.95 },
        SearchResult { id: 2, similarity_score: 0.88 },
    ];

    Ok(results)
}

fn main() -> Result<(), Box<dyn Error>> {
    let inputs = vec!["vector_a", "vector_b"];

    match perform_search("user_query", &inputs) {
        Ok(results) => {
            println!("Search successful. Found {} results.", results.len());
        }
        Err(e) => {
            println!("Error encountered during search: {}", e);
        }
    }

    let bad_inputs = vec![];
    match perform_search("query", &bad_inputs) {
        Ok(_) => {},
        Err(e) => {
            println!("Successfully caught expected error for empty data set: {}", e);
        }
    }

    Ok(())
}

use std::fs;
use std::path::Path;

struct AppConfig {
    setting_a: String,
    setting_b: u32,
}

impl AppConfig {
    fn load(path: &Path) -> Result<Self, std::io::Error> {
        let contents = fs::read_to_string(path)?;
        let mut lines = contents.trim().lines();

        let setting_a = match lines.next() {
            Some(line) => line.split(':').nth(1).unwrap_or(&"default").to_string(),
            None => "default".to_string(),
        };

        let setting_b: u32 = match lines.next() {
            Some(line) => line.split('#').nth(1).and_then(|s| s.parse::<u32>().ok()).unwrap_or(0),
            None => 0,
        };

        Ok(AppConfig {
            setting_a,
            setting_b,
        })
    }

    fn display(&self) {
        println!("Successfully loaded settings: A='{}', B={}", self.setting_a, self.setting_b);
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let config_path = Path::new("settings.conf");

    match AppConfig::load(config_path) {
        Ok(config) => {
            config.display();
        }
        Err(e) => {
            eprintln!("Could not load configuration file: {}. Using fallback settings.", e);
            // In a real app, you'd initialize with safe defaults here.
        }
    }

    Ok(())
}

use std::collections::HashMap;
use std::error::Error;
use std::fmt;

#[derive(Debug)]
struct CalculationError {
    message: String,
}
impl From<std::io::Error> for CalculationError {
    fn from(err: std::io::Error) -> Self {
        CalculationError { message: err.to_string() }
    }
}

impl fmt::Display for CalculationError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{} Error", self.message)
    }
}
impl Error for CalculationError {}

type Result<T> = std::result::Result<T, Box<dyn Error + Send + Sync>>;

fn calculate_feature_covariance(data: &[f64]) -> Result<f64> {
    if data.is_empty() {
        return Err(Box::new(CalculationError { message: "Input array is empty".to_string() }));
    }
    let sum: f64 = data.iter().sum();
    let mean = sum / (data.len() as f64);
    let variance: f64 = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / ((data.len() - 1) as f64).max(1.0);
    Ok(variance)
}

fn process_feature_batch(matrix: &[Vec<f64>]) -> HashMap<String, f64> {
    let mut results: HashMap<String, f64> = HashMap::new();
    for (i, feature_data) in matrix.iter().enumerate() {
        match calculate_feature_covariance(feature_data) {
            Ok(cov) => { 
                let key = format!("Feature_{}_", i);
                results.insert(key, cov);
            },
            Err(e) => { 
                println!("Skipping computation for feature {} due to error: {}", i, e);
            }
        }
    }
    results
}

fn main() -> Result<()> {
    let matrix_data: Vec<Vec<f64>> = vec![ 
        vec![1.0, 2.0, 3.0], 
        vec![10.0, f64::NAN, 30.0], 
        vec![] 
    ];
    let final_results = process_feature_batch(&matrix_data);
    println!("Final successful results: {:?}", final_results);
    Ok(())
}

use std::fmt;

struct ProcessingError { 
    kind: String,
    message: String,
}

impl fmt::Display for ProcessingError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Processing Error: {} - {}", self.kind, self.message)
    }
}

impl std::error::Error for ProcessingError {} 

fn validate_input(data: &str) -> Result<String, ProcessingError> {
    if data.is_empty() {
        return Err(ProcessingError { 
            kind: "Validation Failure".to_string(), 
            message: "Input string cannot be empty.".to_string()
        });
    }
    if data.len() > 1024 {
        return Err(ProcessingError { 
            kind: "Size Constraint Exceeded".to_string(), 
            message: format!("Data is too large, max allowed size is 1024 bytes.")
        });
    }
    Ok(data.to_uppercase())
}

fn process_request(raw_json: &str) -> Result<String, Box<dyn std::error::Error>> {
    let validated_data = validate_input(raw_json)?;
    println!("Successfully validated data: {}", validated_data);
    Ok(format!("Processed OK for: {}", validated_data))
}

