use std::fmt;

struct DataPoint { 
    timestamp: i64,
    value: f64,
}

#[derive(Debug)]
struct CalculationError { 
    message: String,
    data_index: usize,
}

impl fmt::Display for CalculationError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Error at data index {}: {}", self.data_index, self.message)
    }
}

impl std::error::Error for CalculationError {} 

fn calculate_z_score(window: &[f64]) -> Result<f64, Box<dyn std::error::Error>> {
    if window.is_empty() {
        return Err(Box::new(CalculationError { message: String::from("Cannot calculate score on empty window"), data_index: 0 }));
    }
    let sum: f64 = window.iter().sum();
    let mean = sum / (window.len() as f64);
    let variance_sum: f64 = window.iter().map(|&val| (val - mean).powi(2)).sum();
    let std_dev = (variance_sum / (window.len() as f64)).sqrt();
    if std_dev == 0.0 {
        return Err(Box::new(CalculationError { message: String::from("Standard deviation is zero") , data_index: window.len() - 1 }));
    }
    Ok(std_dev)
}

fn process_data(data: &[DataPoint]) -> Result<Vec<(usize, f64)>, Box<dyn std::error::Error>> {
    let mut anomalies = Vec::new();
    const WINDOW_SIZE: usize = 5;

    for i in (WINDOW_SIZE - 1)..data.len() {
        let window_values: Vec<f64> = data[i-WINDOW_SIZE+1..=i].iter().map(|dp| dp.value).collect();
        match calculate_z_score(&window_values) {
            Ok(std_dev) => { 
                let current_value = data[i].value;
                if std_dev > 0.0 && (current_value / std_dev).abs() > 3.0 {
                    anomalies.push((i, std_dev));
                }
            },
            Err(e) => { 
                println!("Skipping window due to failure: {}", e);
            }
        }
    }
    Ok(anomalies)
}

fn main() {
    let data_ok = vec![
        DataPoint{timestamp: 1, value: 10.0},
        DataPoint{timestamp: 2, value: 10.5},
        DataPoint{timestamp: 3, value: 9.8},
        DataPoint{timestamp: 4, value: 10.2},
        DataPoint{timestamp: 5, value: 10.1}, 
        DataPoint{timestamp: 6, value: 25.0} // Anomaly
    ];

    match process_data(&data_ok) {
        Ok(anomalies) => println!("Successfully found potential anomalies: {:?}", anomalies),
        Err(e) => eprintln!("Fatal processing error: {}", e)
    }
}
